body:
Hi,

I got a testcast whose behavior was not my expectation.

```verilog
module t (
    input   logic     clk,
    input   logic     mask,
    output  logic     dout
);
logic      d0;
logic      dpp[1:0];
always @ (posedge clk) begin
    d0 <= ~d0;
end
always @ (*) begin
    dpp[0] = d0;
    dout   = dpp[1];
end
always @ (*) begin
    dpp[1] = 0; // This is the key statement.
    dpp[1] = dpp[0] & mask;
end
endmodule
```
```cpp
// sim_main.cpp
#include "Vdemo.h"
#include "verilated.h"
vluint64_t main_time = 0;
double sc_time_stamp() { return main_time; }
int main(int argc, char** argv, char** env) {
    Verilated::commandArgs(argc, argv);
    Vdemo* top = new Vdemo;
    top->mask = 0x1;
    printf("  clk  dpp[0]  dpp[1]\n");
    while (!Verilated::gotFinish() && main_time < 20) {
        top->eval();
        printf("   %d     %d      %d\n",
            top->clk,
            top->t__DOT__dpp[0],
            top->t__DOT__dpp[1]);
        main_time++;
        top->clk = !top->clk;
    }
    delete top;
    exit(0);
}
```
```txt
// screen output
  clk  dpp[0]  dpp[1]
   0     0      0
   1     1      0
   0     1      1
   1     0      1
   0     0      0
   1     1      0
   0     1      1
   1     0      1
   0     0      0
   1     1      0
   0     1      1
   1     0      1
   0     0      0
   1     1      0
   0     1      1
   1     0      1
   0     0      0
   1     1      0
   0     1      1
   1     0      1
```
The result shows that `dpp[0]` toggles at posedge of `clk` and  `dpp[1]` toggles at negedge of `clk`, but they should change simultaneously.

I tried to study the source code to find out the reason, and then, I found the the comments in the source code like this:
https://github.com/verilator/verilator/blob/222ca4b009baec47f04e99d32373b3a1fd440d05/src/V3Order.cpp#L1043-L1055

May I ask why you make this assumption? It seems you are doing some optimization by reducing the scale of the graph, but It may cause some problem.
If this is your deliberate decision, I think you'd better give some warning here.

Thanks.

Best regards.
